input.command:
RUN_ID="${ZEALT_RUN_ID}" && \
API_KEY="${HOOKDECK_API_KEY}" && \
SOURCE_NAME="source-${RUN_ID}" && \
echo "Creating source: ${SOURCE_NAME}" && \
curl -s -X POST "https://api.hookdeck.com/2025-07-01/sources" \
  -H "Authorization: Bearer ${API_KEY}" \
  -H "Content-Type: application/json" \
  -d "{
    \"name\": \"${SOURCE_NAME}\",
    \"type\": \"WEBHOOK\",
    \"config\": {
      \"auth_type\": \"BASIC_AUTH\",
      \"auth\": {
        \"username\": \"eval-user\",
        \"password\": \"eval-pass\"
      },
      \"custom_response\": {
        \"content_type\": \"json\",
        \"body\": \"{\\\"ok\\\": true, \\\"id\\\": \\\"abc\\\"}\"
      }
    }
  }" | tee /tmp/source_response.json
